import socket
import json
import threading

class GameServer:
    def __init__(self, host='0.0.0.0', port=12345):
        self.host = host
        self.port = port
        self.players = []
        self.game_state = {'level': 1, 'max_players': 10, 'current_players': 0}
        self.server_socket = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self.server_socket.bind((self.host, self.port))
        print(f"Server started on {self.host}:{self.port}")

    def start(self):
        threading.Thread(target=self.listen_for_queries, daemon=True).start()

    def listen_for_queries(self):
        while True:
            data, addr = self.server_socket.recvfrom(1024)
            if data.decode() == 'STATUS':
                self.send_status(addr)

    def send_status(self, addr):
        response = {
            'players': self.players,
            'game_state': self.game_state
        }
        response_data = json.dumps(response).encode('utf-8')
        self.server_socket.sendto(response_data, addr)

    def add_player(self, player_name):
        if self.game_state['current_players'] < self.game_state['max_players']:
            self.players.append(player_name)
            self.game_state['current_players'] += 1

    def remove_player(self, player_name):
        if player_name in self.players:
            self.players.remove(player_name)
            self.game_state['current_players'] -= 1

if __name__ == "__main__":
    server = GameServer()
    server.start()

    # Example usage
    server.add_player("Player1")
    server.add_player("Player2")